  1	import * as React from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	
  4	import { TemplateModel, V1Template } from '@kubevirt-ui/kubevirt-api/console';
  5	import DataVolumeModel from '@kubevirt-ui/kubevirt-api/console/models/DataVolumeModel';
  6	import { V1beta1DataSource } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
  7	import { AnnotationsModal } from '@kubevirt-utils/components/AnnotationsModal/AnnotationsModal';
  8	import CloneTemplateModal from '@kubevirt-utils/components/CloneTemplateModal/CloneTemplateModal';
  9	import DeleteModal from '@kubevirt-utils/components/DeleteModal/DeleteModal';
 10	import { LabelsModal } from '@kubevirt-utils/components/LabelsModal/LabelsModal';
 11	import Loading from '@kubevirt-utils/components/Loading/Loading';
 12	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 13	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 14	import { useLastNamespacePath } from '@kubevirt-utils/hooks/useLastNamespacePath';
 15	import { asAccessReview } from '@kubevirt-utils/resources/shared';
 16	import {
 17	  Action,
 18	  k8sDelete,
 19	  k8sPatch,
 20	  useAccessReview,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	
 23	import useEditTemplateAccessReview from '../../details/hooks/useIsTemplateEditable';
 24	import {
 25	  NO_DELETE_TEMPLATE_PERMISSIONS,
 26	  NO_EDIT_TEMPLATE_PERMISSIONS,
 27	} from '../../utils/constants';
 28	import EditBootSourceModal from '../components/EditBootSourceModal';
 29	import {
 30	  createDataVolume,
 31	  getBootDataSource,
 32	  getEditBootSourceRefDescription,
 33	  hasEditableBootSource,
 34	} from '../editBootSource';
 35	
 36	type useVirtualMachineTemplatesActionsProps = (
 37	  template: V1Template,
 38	) => [actions: Action[], onLazyActions: () => void];
 39	
 40	export const EDIT_TEMPLATE_ID = 'edit-template';
 41	const useVirtualMachineTemplatesActions: useVirtualMachineTemplatesActionsProps = (
 42	  template: V1Template,
 43	) => {
 44	  const { t } = useKubevirtTranslation();
 45	  const { hasEditPermission, isCommonTemplate } = useEditTemplateAccessReview(template);
 46	  const { createModal } = useModal();
 47	  const navigate = useNavigate();
 48	  const [bootDataSource, setBootDataSource] = React.useState<V1beta1DataSource>();
 49	  const [loadingBootSource, setLoadingBootSource] = React.useState(true);
 50	  const editableBootSource = hasEditableBootSource(bootDataSource);
 51	  const lastNamespacePath = useLastNamespacePath();
 52	
 53	  const [canDeleteTemplate] = useAccessReview({
 54	    namespace: template?.metadata?.namespace,
 55	    resource: TemplateModel.plural,
 56	    verb: 'delete',
 57	  });
 58	
 59	  const [canWriteToDataSourceNs] = useAccessReview(
 60	    asAccessReview(
 61	      DataVolumeModel,
 62	      createDataVolume(
 63	        bootDataSource?.spec?.source?.pvc?.name,
 64	        bootDataSource?.spec?.source?.pvc?.namespace,
 65	        {},
 66	      ),
 67	      'create',
 68	    ),
 69	  );
 70	
 71	  const goToTemplatePage = React.useCallback(
 72	    (clonedTemplate: V1Template) => {
 73	      navigate(
 74	        `/k8s/ns/${clonedTemplate.metadata.namespace}/templates/${clonedTemplate.metadata.name}`,
 75	      );
 76	    },
 77	    [navigate],
 78	  );
 79	
 80	  const onLazyActions = React.useCallback(async () => {
 81	    if (!bootDataSource) {
 82	      const dataSource = await getBootDataSource(template);
 83	      setBootDataSource(dataSource);
 84	    }
 85	    setLoadingBootSource(false);
 86	  }, [bootDataSource, template]);
 87	
 88	  const onDelete = async () => {
 89	    await k8sDelete({
 90	      model: TemplateModel,
 91	      resource: template,
 92	    }).then(() => navigate(`/k8s/${lastNamespacePath}/templates`));
 93	  };
 94	
 95	  const actions = [
 96	    {
 97	      accessReview: asAccessReview(TemplateModel, template, 'patch'),
 98	      cta: () =>
 99	        // lead to the template details page
100	        navigate(`/k8s/ns/${template.metadata.namespace}/templates/${template.metadata.name}`),
101	      id: EDIT_TEMPLATE_ID,
102	      label: t('Edit'),
103	    },
104	    {
105	      accessReview: asAccessReview(TemplateModel, template, 'create'),
106	      cta: () =>
107	        createModal(({ isOpen, onClose }) => (
108	          <CloneTemplateModal
109	            isOpen={isOpen}
110	            obj={template}
111	            onClose={onClose}
112	            onTemplateCloned={goToTemplatePage}
113	          />
114	        )),
115	      id: 'clone-template',
116	      label: t('Clone'),
117	    },
118	    {
119	      accessReview: asAccessReview(TemplateModel, template, 'patch'),
120	      cta: () =>
121	        navigate(
122	          `/k8s/ns/${template.metadata.namespace}/templates/${template.metadata.name}/disks`,
123	        ),
124	      description:
125	        (isCommonTemplate && t('Red Hat template cannot be edited')) ||
126	        (!hasEditPermission && t(NO_EDIT_TEMPLATE_PERMISSIONS)),
127	      disabled: isCommonTemplate || !hasEditPermission,
128	      id: 'edit-boot-source',
129	      label: t('Edit boot source'),
130	    },
131	    {
132	      accessReview: asAccessReview(TemplateModel, template, 'patch'),
133	      cta: () =>
134	        createModal(({ isOpen, onClose }) => (
135	          <EditBootSourceModal
136	            dataSource={bootDataSource}
137	            isOpen={isOpen}
138	            obj={template}
139	            onClose={onClose}
140	          />
141	        )),
142	      description:
143	        (!loadingBootSource || !canWriteToDataSourceNs) &&
144	        getEditBootSourceRefDescription(bootDataSource, canWriteToDataSourceNs),
145	      disabled: !editableBootSource || !canWriteToDataSourceNs,
146	      id: 'edit-boot-source-ref',
147	      label: (
148	        <>
149	          {t('Edit boot source reference')} {loadingBootSource && <Loading />}
150	        </>
151	      ),
152	    },
153	    {
154	      accessReview: asAccessReview(TemplateModel, template, 'patch'),
155	      cta: () =>
156	        createModal(({ isOpen, onClose }) => (
157	          <LabelsModal
158	            onLabelsSubmit={(labels) =>
159	              k8sPatch({
160	                data: [
161	                  {
162	                    op: 'replace',
163	                    path: '/metadata/labels',
164	                    value: labels,
165	                  },
166	                ],
167	                model: TemplateModel,
168	                resource: template,
169	              })
170	            }
171	            isOpen={isOpen}
172	            obj={template}
173	            onClose={onClose}
174	          />
175	        )),
176	      description:
177	        (isCommonTemplate && t('Labels cannot be edited for Red Hat templates')) ||
178	        (!hasEditPermission && t(NO_EDIT_TEMPLATE_PERMISSIONS)),
179	      disabled: isCommonTemplate || !hasEditPermission,
180	      id: 'edit-labels',
181	      label: t('Edit labels'),
182	    },
183	    {
184	      accessReview: asAccessReview(TemplateModel, template, 'patch'),
185	      cta: () =>
186	        createModal(({ isOpen, onClose }) => (
187	          <AnnotationsModal
188	            onSubmit={(updatedAnnotations) =>
189	              k8sPatch({
190	                data: [
191	                  {
192	                    op: 'replace',
193	                    path: '/metadata/annotations',
194	                    value: updatedAnnotations,
195	                  },
196	                ],
197	                model: TemplateModel,
198	                resource: template,
199	              })
200	            }
201	            isOpen={isOpen}
202	            obj={template}
203	            onClose={onClose}
204	          />
205	        )),
206	      description:
207	        (isCommonTemplate && t('Annotations cannot be edited for Red Hat templates')) ||
208	        (!hasEditPermission && t(NO_EDIT_TEMPLATE_PERMISSIONS)),
209	      disabled: isCommonTemplate || !hasEditPermission,
210	      id: 'edit-annotations',
211	      label: t('Edit annotations'),
212	    },
213	    {
214	      accessReview: asAccessReview(TemplateModel, template, 'delete'),
215	      cta: () =>
216	        createModal(({ isOpen, onClose }) => (
217	          <DeleteModal
218	            headerText={t('Delete VirtualMachine Template?')}
219	            isOpen={isOpen}
220	            obj={template}
221	            onClose={onClose}
222	            onDeleteSubmit={onDelete}
223	          />
224	        )),
225	      description:
226	        (isCommonTemplate && t('Red Hat template cannot be deleted')) ||
227	        (!canDeleteTemplate && t(NO_DELETE_TEMPLATE_PERMISSIONS)),
228	      disabled: isCommonTemplate || !canDeleteTemplate,
229	      id: 'delete-template',
230	      label: t('Delete'),
231	    },
232	  ];
233	
234	  return [actions, onLazyActions];
235	};
236	
237	export default useVirtualMachineTemplatesActions;

